final:
module RefModule(
  input [31:0] a,
  input [31:0] b,
  output reg [31:0] r
);// Inputs
  wire [31:0] _tap_a = a & {32{1'b1}};

// a: dividend, b: divisor
// Outputs
// r: remainder

// Verilog code for modulo operator
always @(*) begin
  if (b == 0) begin
    r <= 0;
  end else begin
    r <= a % b;
  end
end

endmodule
